<template>
  <div>
    <el-dialog
      :title="dialogTitle"
      :before-close="handleCancelLabelsDialog"
      :visible.sync="dialogIsShow"
      :show-close="false"
      width="30%"
    >
      <div>
        <el-radio-group
          v-model="notesModalType"
          class="result"
          size="small"
          @change="modalInit"
        >
          <el-radio-button label="pass">
            發布已選
          </el-radio-button>
          <el-radio-button label="refuse">
            下架已選
          </el-radio-button>
        </el-radio-group>

        <div class="cont">
          <div
            class="info"
            v-html="modalInfo"
          />
        </div>
      </div>
      <div slot="footer">
        <el-button
          type="primary"
          @click="modalHandle"
        >
          {{ handleText }}
        </el-button>
        <el-button @click="handleCancelLabelsDialog">
          取消
        </el-button>
      </div>
    </el-dialog>
  </div>
</template>

<script>
export default {
  props: {
    dialogIsShow:Boolean,
    auditType:String,
    dufStatus:String
  },
  data () {
    return {
      notesModalType:'pass',
      dialogTitle:null,
      handleText:null,
      modalInfo:null
    }
  },
  computed: {
  },
  watch:{
    dialogIsShow:{
      handler (newValue, oldValue) {
        const {dufStatus} = this.$props;
        if(dufStatus!=null){
          this.$data.notesModalType = dufStatus;
        }
        this.modalInit();
      },
       immediate: true
    }
  },
  mounted () {

  },
  methods: {
    modalInit (){
     const {auditType} = this.$props;
     //console.log('auditType',auditType,dufStatus)
      switch(auditType){
        case 'note':
          this.noteInit();
          break;
        case 'flag':
          this.flagInit();
          break;
      }
    },
    noteInit (){
      const {notesModalType} = this.$data;
       var dialogTitle = '筆記狀態變更';
       var handleText = null;
       var modalInfo = null;
      // console.log('modalInit notesModalType',notesModalType)
       switch(notesModalType){
         case 'pass':
           handleText = '發布';
           modalInfo = '筆記發布點擊「發布」後已選筆記將被加入小程序顯示的隊列，並將適配對應顯示規則；若您希望將所選筆記的顯示位置進行調整，請修改對應排序。';
           break;
         case 'refuse':
           handleText = '下架';
           modalInfo = '點擊「下架」後已選筆記將不會在小程序中的社區中顯示；<br/>同時，已轉發/分享/收藏的連結&入口將失效。';
           break;
       }
       this.$data.dialogTitle = dialogTitle;
       this.$data.handleText = handleText;
       this.$data.modalInfo = modalInfo;
    },
    flagInit (){
      const {notesModalType} = this.$data;
       var dialogTitle = '角標狀態變更';
       var handleText = null;
       var modalInfo = null;
       //console.log('modalInit notesModalType',notesModalType)
       switch(notesModalType){
         case 'pass':
           handleText = '發布';
           modalInfo = '點擊「發布」後，帶有已選角標的筆記將會在小程序社區中顯示顯示對應的角標。';
           break;
         case 'refuse':
           handleText = '下架';
           modalInfo = '點擊「下架」後，帶有已選角標的筆記依舊存在，但不顯示對應角標；';
           break;
       }
       this.$data.dialogTitle = dialogTitle;
       this.$data.handleText = handleText;
       this.$data.modalInfo = modalInfo;
    },
    handleCancelLabelsDialog () {
      this.$emit('cancelLabelsDialog',false)
    },
    modalHandle (){
      const {notesModalType} = this.$data;
      var params = {status:notesModalType=='pass'?1:4}
      //console.log('handleAudit',params)
      this.$emit('modalHandle',params)
    }
  }
}
</script>
<style scoped lang="css">
.result{position: absolute; top:20px; right: 20px;}
.btn-bar{margin-top: 30px; text-align: right;}
</style>
